SELECT COUNT(DISTINCT PB.PK) AS QUANTIDADE FROM LATTES_P_PRODBIB PP JOIN SERVIDOR S ON S.PK_SIAPE = PP.FK_SIAPE JOIN LATTES_PRODBIB PB ON PB.PK = PP.FK_PRODBIB WHERE LOWER(PB.TIPO) = LOWER('trabalho em evento') AND TRIM(LOWER(COALESCE(PB.ANO, ''))) = '2023' AND LOWER(S.GENERO) = LOWER('masculino') AND LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%administra%' AND LOWER(COALESCE(S.SIGLA_CAMPUS, '')) = 'uru'